function initQuizSetup(){const n=document.querySelectorAll(".custom-dropdown");n.length!==0&&n.forEach(n=>{const t=n.querySelector(".btn-dropdown"),i=n.querySelector(".dropdown-hidden-input"),r=n.querySelectorAll(".dropdown-item"),u=t.querySelector(".selected-text");t&&i&&u&&r.forEach(n=>{n.addEventListener("click",t=>{t.preventDefault(),r.forEach(n=>n.classList.remove("active")),n.classList.add("active"),i.value=n.getAttribute("data-value"),u.innerText=n.innerText})})})}document.readyState==="loading"?document.addEventListener("DOMContentLoaded",initQuizSetup):initQuizSetup();